# Conceptual sketch of LCM-LoRA setup
import torch
import torch.nn as nn


class LoRALinear(nn.Module):
    """Low-rank adapter wrapping a frozen linear layer."""

    def __init__(self, base: nn.Linear, rank: int = 4, alpha: float = 1.0):
        super().__init__()
        d_in, d_out = base.in_features, base.out_features
        self.base = base
        for p in self.base.parameters():
            p.requires_grad = False  # freeze base weights
        self.A = nn.Parameter(torch.randn(d_in, rank) * 0.01)
        self.B = nn.Parameter(torch.zeros(rank, d_out))
        self.scale = alpha / rank

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        return self.base(x) + (x @ self.A @ self.B) * self.scale


def inject_lora(model: nn.Module, rank: int = 4, alpha: float = 1.0):
    """Replace all Linear layers in attention with LoRALinear."""
    for name, module in model.named_children():
        if isinstance(module, nn.Linear) and 'attn' in name.lower():
            setattr(model, name, LoRALinear(module, rank=rank, alpha=alpha))
        else:
            inject_lora(module, rank, alpha)


def count_trainable(model: nn.Module) -> int:
    return sum(p.numel() for p in model.parameters() if p.requires_grad)


# Example usage:
# inject_lora(unet, rank=8)
# trainable_params = count_trainable(unet)
# Full U-Net: ~1B params; LoRA adapters: ~1M params (1000× reduction)
